using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search and page fetching capabilities via the Wikipedia API.
/// </summary>
public sealed class WebSearchTool : IDisposable
{
    private readonly HttpClient _httpClient = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0 (educational-demo)" }
        }
    };

    [Description("Search the web for information on a topic. Returns a list of results with titles and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={Uri.EscapeDataString(query)}&srlimit=5&format=json";

        var doc = await _httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);
        var results = doc.GetProperty("query").GetProperty("search");

        if (results.GetArrayLength() == 0)
        {
            return "No results found.";
        }

        var entries = new List<string>();
        foreach (var item in results.EnumerateArray())
        {
            var title = item.GetProperty("title").GetString();
            var snippet = StripHtml(item.GetProperty("snippet").GetString() ?? "");
            entries.Add($"- {title}: {snippet}");
        }

        return $"Search results for \"{query}\":\n{string.Join("\n", entries)}";
    }

    [Description("Fetch the summary content of a Wikipedia page by its title. Use this to get detailed information after searching.")]
    public async Task<string> FetchPageContentAsync(
        [Description("The exact Wikipedia page title to fetch (e.g. \"Quantum computing\")")] string title,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://en.wikipedia.org/api/rest_v1/page/summary/{Uri.EscapeDataString(title)}";

        try
        {
            var doc = await _httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);

            var pageTitle = doc.GetProperty("title").GetString();
            var extract = doc.GetProperty("extract").GetString() ?? "No content available.";
            var pageUrl = doc.TryGetProperty("content_urls", out var urls)
                ? urls.GetProperty("desktop").GetProperty("page").GetString()
                : null;

            var result = $"Title: {pageTitle}\n\n{extract}";
            if (pageUrl is not null)
            {
                result += $"\n\nSource: {pageUrl}";
            }

            return result;
        }
        catch (HttpRequestException)
        {
            return $"Could not fetch page \"{title}\". Try a different title from the search results.";
        }
    }

    private static string StripHtml(string html)
    {
        return System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", "");
    }

    public void Dispose() => _httpClient.Dispose();
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides in-memory note-taking capabilities for recording research findings.
/// </summary>
public sealed class NotepadTool
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record important findings during research.")]
    public string TakeNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes. Use this to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

