using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

using var webSearch = new WebSearchTool();
var notepad = new NotepadTool();

List<AITool> tools =
[
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(webSearch.FetchPageContentAsync),
    AIFunctionFactory.Create(notepad.TakeNote),
    AIFunctionFactory.Create(notepad.GetNotes),
];

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research assistant. When given a topic:

        1. Search the web with several varied queries to find relevant information.
        2. Fetch page content for the most promising results to get detailed information.
        3. Take notes on every key finding — facts, dates, explanations, and sources.
        4. After gathering enough information, review your notes and produce a
           well-organized, comprehensive summary with source attribution.

        Be methodical: search broadly, read deeply, take notes as you go, then summarize.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics using web search and note-taking",
    tools: tools);

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();

